            } else {
                "正常".to_string()
            },
            monitor_action.to_string(),
            "collector warning、官方源失败、P0 missing_info、USDC/USD 偏离、储备异常、Circle/核心链状态异常或监管 P0。".to_string(),
            contradictions,
        ),
        "daily-monitor" => (
            if blocked {
