            } else {
                "观察".to_string()
            },
            if blocked {
                "停止输出增强；先完成信用层、来源或监管 P0 复核。".to_string()
            } else {
                "维持观察，不因单日行情改框架；等待周度或事件复核确认。".to_string()
            },
            "Circle Transparency 更新、监管官方公告、USDC/USD 偏离、储备收益率刷新或 Base/Circle 状态异常。".to_string(),
            contradictions,
        ),
        "weekly-review" => (
            if blocked {
