            } else {
                "中性".to_string()
            },
            if blocked {
                "SEC/公司披露或关键财务输入阻断，先补事实锚。".to_string()
            } else {
                "完成事实层复核；电话会和管理层 Q&A 后再更新叙事层。".to_string()
            },
            "最新 10-Q/10-K、shareholder letter、earnings call transcript、FY 指引更新或 RLDC margin 低于 38%。".to_string(),
            contradictions,
